import{_ as a,o as d,c as i,ag as t}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"นามแฝง Mkdir | Dotfiles (TH)","titleTemplate":":title","description":"คำสั่งสร้างโฟลเดอร์แบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","frontmatter":{"title":"นามแฝง Mkdir | Dotfiles","description":"คำสั่งสร้างโฟลเดอร์แบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","lang":"th-TH","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"นามแฝง Mkdir | Dotfiles preview","canonical":"/th/aliases/mkdir/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"นามแฝง Mkdir","pageType":"docs","schemaType":"WebPage","permalink":"/th/aliases/mkdir/"},"headers":[],"relativePath":"th/aliases/mkdir/index.md","filePath":"th/aliases/mkdir/index.md","lastUpdated":1773010926000}'),o={name:"th/aliases/mkdir/index.md"};function l(r,e,c,s,m,n){return d(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="นามแฝง-mkdir" tabindex="-1">นามแฝง Mkdir <a class="header-anchor" href="#นามแฝง-mkdir" aria-label="Permalink to &quot;นามแฝง Mkdir&quot;">​</a></h1><p>คำสั่งสร้างโฟลเดอร์แบบสั้น</p><p>หน้านี้แนะนำกลุ่มนามแฝงหนึ่งกลุ่มและทางลัดคำสั่งทั่วไป อ่านหน้านี้ก่อนเพื่อทำความเข้าใจแบบแผนการตั้งชื่อ อินพุตที่คาดหวัง และรูปแบบการดำเนินการที่ปลอดภัย จากนั้นเปิดภาคผนวกอ้างอิงเพื่อดูรายการคำสั่งทั้งหมดและไวยากรณ์ที่แน่นอน นามแฝงเหล่านี้ลดการพิมพ์ซ้ำและรักษาพฤติกรรมเวิร์กโฟลว์ที่สม่ำเสมอบน macOS, Linux และ WSL</p><h2 id="เมื่อใดควรใช้" tabindex="-1">เมื่อใดควรใช้ <a class="header-anchor" href="#เมื่อใดควรใช้" aria-label="Permalink to &quot;เมื่อใดควรใช้&quot;">​</a></h2><p>ใช้หน้านี้ก่อนการทำงานเชลล์ประจำวันเมื่อคุณต้องการรูปแบบคำสั่งที่คาดเดาได้</p><h2 id="สิ่งที่รวมอยู่" tabindex="-1">สิ่งที่รวมอยู่ <a class="header-anchor" href="#สิ่งที่รวมอยู่" aria-label="Permalink to &quot;สิ่งที่รวมอยู่&quot;">​</a></h2><ul><li>นามแฝง: 6</li><li>ฟังก์ชันตัวช่วย: 0</li><li>ไฟล์ต้นฉบับ: 1</li></ul><h2 id="ตัวอย่างสั้น" tabindex="-1">ตัวอย่างสั้น <a class="header-anchor" href="#ตัวอย่างสั้น" aria-label="Permalink to &quot;ตัวอย่างสั้น&quot;">​</a></h2><ul><li><code>md</code> → <code>mkdir -v</code></li><li><code>mdd</code> → <code>mkdir -pv &quot;$(date +%Y%m%d)&quot; &amp;&amp; cd &quot;$(date +%Y%m%d)&quot;</code></li><li><code>mde</code> → <code>mkdir -pv &quot;$(date +%Y%m%d)-example&quot;</code></li><li><code>mdn</code> → <code>mkdir -pv &quot;$(date +%Y%m%d)-notes&quot;</code></li><li><code>mdt</code> → <code>mkdir -pv &quot;$(date +%H%M%S)&quot;</code></li><li><code>mdw</code> → <code>mkdir -pv &quot;$(date +%Y%m%d)-work&quot;</code></li></ul><h2 id="ขั้นตอนถัดไป" tabindex="-1">ขั้นตอนถัดไป <a class="header-anchor" href="#ขั้นตอนถัดไป" aria-label="Permalink to &quot;ขั้นตอนถัดไป&quot;">​</a></h2><p>เปิดรายการทั้งหมด:</p>',11)])])}const h=a(o,[["render",l]]);export{p as __pageData,h as default};
